function createRenderer() {
  function render(t, context) {
    const ctx = context.mainContext;
    const w = context.width;
    const h = context.height;
    const cx = w / 2;
    const cy = h / 2 + 4;
    ctx.save();
    ctx.globalAlpha = 0.95;
    for (let i = 0; i < 18; i++) {
      const a = t * 1.7 + i * Math.PI * 2 / 18;
      const rx = 260 + Math.sin(t + i) * 26;
      const ry = 96 + Math.cos(t * 0.7 + i) * 18;
      const x = cx + Math.cos(a) * rx;
      const y = cy + Math.sin(a) * ry;
      ctx.fillStyle = i % 3 === 0 ? '#00d4ff' : (i % 3 === 1 ? '#7bd88f' : '#ff5c8a');
      ctx.beginPath();
      ctx.arc(x, y, 4 + (i % 4), 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.restore();
  }
  return { render };
}
